# Generated by openai (o3)
# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(name: 'REGISTRY_URL',  defaultValue: 'docker.io/myteam/app', description: 'Registry and repository (no tag)')
        string(name: 'IMAGE_TAG',     defaultValue: 'latest',               description: 'Image tag to build/push')
        string(name: 'REGISTRY_CREDENTIALS_ID', defaultValue: 'docker-reg-creds', description: 'Credentials ID for registry login')
        string(name: 'DOCKER_CONTEXT', defaultValue: '.', description: 'Docker build context')
    }

    stages {
        stage('Checkout') {
            steps {
                checkout scm
            }
        }

        stage('Build Image') {
            steps {
                sh '''
                    docker build -t $REGISTRY_URL:$IMAGE_TAG $DOCKER_CONTEXT
                '''
            }
        }

        stage('Push Image') {
            steps {
                withCredentials([usernamePassword(credentialsId: params.REGISTRY_CREDENTIALS_ID, usernameVariable: 'REG_USER', passwordVariable: 'REG_PASS')]) {
                    sh '''
                        REGISTRY_HOST=$(echo $REGISTRY_URL | cut -d/ -f1)
                        echo "$REG_PASS" | docker login $REGISTRY_HOST -u "$REG_USER" --password-stdin
                        docker push $REGISTRY_URL:$IMAGE_TAG
                        docker logout $REGISTRY_HOST
                    '''
                }
            }
        }
    }

    post {
        cleanup {
            sh '''
                docker image rm -f $REGISTRY_URL:$IMAGE_TAG || true
            '''
        }
    }
}